const express = require('express');
const WebSocket = require('ws');

const app = express();
const server = app.listen(3000);
const wss = new WebSocket.Server({ server });

let gameState = {}; // Game state here (units, buildings, etc.)

wss.on('connection', (ws) => {
  console.log('Client connected');

  ws.on('message', (data) => {
    const command = JSON.parse(data);
    switch (command.type) {
      case 'build':
        if (!gameState.player[ws.upgrade.toString()].resources.minerals - command.cost.minerals) {
          ws.send(JSON.stringify({ error: 'Not enough minerals' }));
          return;
        }
        gameState.player[ws.upgrade.toString()].resources.minerals -= command.cost.minerals;
        const unit = { ...command.unit, playerId: ws.upgrade.toString() };
        gameState.units.push(unit);
        ws.send(JSON.stringify({ success: 'Unit built' }));
        break;
      case 'attack':
        // Implement attack logic here
        break;
      case 'move':
        // Implement move logic here
        break;
    }
  });

  ws.on('close', () => {
    console.log('Client disconnected');
  });
});